fn trunc(s: &str, n: usize) -> String {
    if s.chars().count() > n {
        let t: String = s.chars().take(n).collect();
        format!("{}…", t)
    } else {
        s.to_string()
    }
}

fn type_chip(t: &str) -> Value {
    let s = trunc(t, 32);
    json!({"tag":"code","props":{"className":"type-chip","title":t},"children":[s]})
}

fn stage_card(s: Value) -> Value {
    let id   = s["id"].as_str().unwrap_or("").to_string();
    let desc = s["description"].as_str().unwrap_or("Unknown stage").to_string();
    let inp  = s["input"].as_str().unwrap_or("Any").to_string();
    let out  = s["output"].as_str().unwrap_or("Any").to_string();
    let sid  = trunc(&id, 8);
    json!({
        "tag":"div","props":{"className":"stage-card"},
        "children":[
            {"tag":"div","props":{"className":"card-header"},"children":[
                {"tag":"span","props":{"className":"card-id"},"children":[sid]}
            ]},
            {"tag":"p","props":{"className":"card-desc"},"children":[desc]},
            {"tag":"div","props":{"className":"card-types"},"children":[
                type_chip(&inp),
                {"tag":"span","props":{"className":"arrow"},"children":["→"]},
                type_chip(&out)
            ]}
        ]
    })
}

fn execute(input: &Value) -> Value {
    let query = input["query"].as_str().unwrap_or("").trim().to_lowercase();
    let limit = input["limit"].as_u64().unwrap_or(12) as usize;
    let catalog: Vec<Value> = match serde_json::from_str(CATALOG_JSON) {
        Ok(v) => v,
        Err(_) => return json!({"tag":"p","props":{},"children":["catalog parse error"]}),
    };
    let raw_query = input["query"].as_str().unwrap_or("").to_string();

    let results: Vec<Value> = if query.is_empty() {
        catalog.into_iter().take(limit).map(stage_card).collect()
    } else {
        let tokens: Vec<String> = query.split_whitespace().map(|s| s.to_string()).collect();
        let mut scored: Vec<(usize, Value)> = catalog.into_iter().filter_map(|s| {
            let desc = s["description"].as_str().unwrap_or("").to_lowercase();
            let inp  = s["input"].as_str().unwrap_or("").to_lowercase();
            let out  = s["output"].as_str().unwrap_or("").to_lowercase();
            let hits = tokens.iter().filter(|t| desc.contains(t.as_str()) || inp.contains(t.as_str()) || out.contains(t.as_str())).count();
            if hits > 0 { Some((hits, s)) } else { None }
        }).collect();
        scored.sort_by(|a, b| b.0.cmp(&a.0));
        scored.into_iter().take(limit).map(|(_, s)| stage_card(s)).collect()
    };

    let count = results.len();
    let subtitle = if count == 0 && !query.is_empty() {
        format!("No stages matched \"{}\"", raw_query)
    } else if count == 0 {
        "Click a hint below, or type to search all 77 stdlib stages".to_string()
    } else if query.is_empty() {
        format!("Showing {} of 77 stages", count)
    } else {
        format!("{} result{} for \"{}\"", count, if count==1 {""} else {"s"}, raw_query)
    };

    let hints = ["sort","text","number","list","json","hash","llm","record","http","embed"];
    let hint_chips: Vec<Value> = hints.iter().map(|h| json!({
        "tag":"button",
        "props":{"className":"hint-chip","onclick":{"$event":"hint","$hint":*h}},
        "children":[*h]
    })).collect();

    let mut children: Vec<Value> = vec![
        json!({"tag":"header","props":{"className":"ex-header"},"children":[
            {"tag":"div","props":{"className":"ex-titles"},"children":[
                {"tag":"h1","props":{"className":"ex-title"},"children":[
                    "Stage ",{"tag":"span","props":{},"children":["Explorer"]}
                ]},
                {"tag":"p","props":{"className":"ex-subtitle"},"children":[
                    "Browse the Noether standard library"
                ]}
            ]},
            {"tag":"span","props":{"className":"ex-badge"},"children":["noether 0.1.0"]}
        ]}),
        json!({"tag":"div","props":{"className":"search-wrap"},"children":[
            {"tag":"input","props":{
                "type":"text","className":"search-input",
                "placeholder":"Search… sort, text, http, llm",
                "value": raw_query.as_str(),
                "oninput":{"$event":"type"}
            },"children":[]},
            {"tag":"button","props":{"className":"search-btn","onclick":{"$event":"search"}},"children":["Search"]}
        ]}),
        json!({"tag":"p","props":{"className":"result-count"},"children":[subtitle]}),
    ];

    if !results.is_empty() {
        children.push(json!({"tag":"div","props":{"className":"cards-grid"},"children": results}));
    } else {
        children.push(json!({"tag":"div","props":{"className":"empty-state"},"children":[
            {"tag":"strong","props":{},"children":["What are you looking for?"]},
            {"tag":"div","props":{"className":"hint-chips"},"children": hint_chips}
        ]}));
    }

    children.push(json!({"tag":"footer","props":{"className":"ex-footer"},"children":[
        {"tag":"span","props":{},"children":["Built with "]},
        {"tag":"a","props":{"href":"https://github.com/solv-ai/noether","target":"_blank"},"children":["Noether"]},
        {"tag":"span","props":{"className":"dot"},"children":[" · "]},
        {"tag":"span","props":{},"children":["agent-native verified composition"]}
    ]}));

    json!({"tag":"div","props":{"className":"explorer-root"},"children": children})
}
